// Sedona by default; clamp radius so nobody can turn this into an open proxy for the whole sky.
const q = $input.first().json.query || {};
const lat = Number(q.lat) || 34.8697;
const lon = Number(q.lon) || -111.7610;
let radius = Number(q.radius) || 45;
radius = Math.max(10, Math.min(radius, 100));
return [{ json: { lat, lon, radius } }];

// Trim to exactly what the site's aircraft.js needs. If adsb.lol is down
// or the shape changes, we return an empty list — never invented traffic.
const d = $input.first().json || {};
const list = Array.isArray(d.ac) ? d.ac : [];
const aircraft = list
  .filter((a) => a && a.dir != null && a.alt_baro != null && a.alt_baro !== 'ground')
  .slice(0, 6)
  .map((a) => ({
    flight: (a.flight || '').trim(),
    dir: a.dir,
    dst: a.dst || 0,
    alt_baro: a.alt_baro,
    track: a.track != null ? a.track : a.dir,
  }));
return [{ json: { ok: true, aircraft } }];
